#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#pragma OPENCL EXTENSION cl_khr_fp16 : enable

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 0
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 1
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 1
#endif

#ifndef BLOCK_STRIDED
#define BLOCK_STRIDED 0
#endif

#ifndef class_T
#define class_T float
#endif

#ifndef blockdim
#define blockdim 256
#endif

#ifdef ENABLE_HP
typedef short cl_half2[2];
#endif

__attribute__((noinline))
class_T bench_block(const class_T* data, class_T f) {
    class_T sum = 0;

    #ifdef ENABLE_HP
    if (sizeof(class_T) == 2) {
        cl_half2 f_vec;
        f_vec[0] = ((const cl_half*)data)[0];
        f_vec[1] = ((const cl_half*)data)[1];

        for (size_t i = 0; i < ELEMENTS_PER_THREAD; i++) {
            cl_half2 t_vec;
            t_vec[0] = ((const cl_half*)data)[i*2];
            t_vec[1] = ((const cl_half*)data)[i*2+1];

            for (size_t j = 0; j < COMPUTE_ITERATIONS / 8; j++) {
                t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0];
                t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1];
                t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0];
                t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1];
                t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0];
                t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1];
                t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0];
                t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1];
                t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0];
                t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1];
                t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0];
                t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1];
                t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0];
                t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1];
                t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0];
                t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1];
            }

            int rem = COMPUTE_ITERATIONS % 8;
            if (rem > 0) { t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0]; t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1]; }
            if (rem > 1) { t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0]; t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1]; }
            if (rem > 2) { t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0]; t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1]; }
            if (rem > 3) { t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0]; t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1]; }
            if (rem > 4) { t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0]; t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1]; }
            if (rem > 5) { t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0]; t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1]; }
            if (rem > 6) { t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0]; t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1]; }

            sum += t_vec[0] + t_vec[1];
        }
        return sum;
    }
    #endif

    // Generic implementation for float, double, int
    class_T f_vec[8];
    for(int k=0; k<8; k++) f_vec[k] = f;

    for (size_t i = 0; i < ELEMENTS_PER_THREAD; i++) {
        class_T t_vec[8];
        for(int k=0; k<8; k++) t_vec[k] = data[i];

        for (size_t j = 0; j < COMPUTE_ITERATIONS / 8; j++) {
            t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0];
            t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1];
            t_vec[2] = t_vec[2] * t_vec[2] + f_vec[2];
            t_vec[3] = t_vec[3] * t_vec[3] + f_vec[3];
            t_vec[4] = t_vec[4] * t_vec[4] + f_vec[4];
            t_vec[5] = t_vec[5] * t_vec[5] + f_vec[5];
            t_vec[6] = t_vec[6] * t_vec[6] + f_vec[6];
            t_vec[7] = t_vec[7] * t_vec[7] + f_vec[7];
        }

        int rem = COMPUTE_ITERATIONS % 8;
        if (rem > 0) t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0];
        if (rem > 1) t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1];
        if (rem > 2) t_vec[2] = t_vec[2] * t_vec[2] + f_vec[2];
        if (rem > 3) t_vec[3] = t_vec[3] * t_vec[3] + f_vec[3];
        if (rem > 4) t_vec[4] = t_vec[4] * t_vec[4] + f_vec[4];
        if (rem > 5) t_vec[5] = t_vec[5] * t_vec[5] + f_vec[5];
        if (rem > 6) t_vec[6] = t_vec[6] * t_vec[6] + f_vec[6];

        sum += t_vec[0] + t_vec[1] + t_vec[2] + t_vec[3] + t_vec[4] + t_vec[5] + t_vec[6] + t_vec[7];
    }
    return sum;
}

__kernel void benchmark_func(class_T seed, const __global class_T* src) {
    size_t global_id = get_global_id(0);
    size_t local_id = get_local_id(0);
    size_t group_id = get_group_id(0);

    size_t stride;
    if (BLOCK_STRIDED) {
        stride = blockdim * ELEMENTS_PER_THREAD * FUSION_DEGREE;
    } else {
        stride = get_global_size(0) * ELEMENTS_PER_THREAD * FUSION_DEGREE;
    }

    size_t base_idx = global_id * ELEMENTS_PER_THREAD * FUSION_DEGREE;

    class_T local_sum = 0;

    for (size_t f = 0; f < FUSION_DEGREE; f++) {
        size_t current_idx = base_idx + f * ELEMENTS_PER_THREAD;
        class_T f_val = src[current_idx];

        // Pass the pointer to the start of the chunk for this fusion step
        local_sum += bench_block(src + current_idx, f_val);
    }

    // Note: Global reduction to update src[0] with total sum is omitted due to 
    // OpenCL 1.2 constraints on atomic floats/doubles and single-pass complexity.
    // This matches the computational core of the algorithm.
}
